import type { Ability, AdventureDefinition, AdventureEventDefinition, AdventureNode, DamageType, EnemyTemplate, GearItem, GearSetBonusDefinition, Talent } from "./types";
import { createStatusEffect } from "./statusEffects";

type AbilityDefinition = Omit<Ability, "types"> & { types?: DamageType[] };

const ABILITY_TYPE_OVERRIDES: Record<string, DamageType[]> = {
  guard: ["physical"],
  PoisonStab: ["physical", "arcane"],
  PoisonCloud: ["arcane"],
  Contagion: ["arcane"],
  Stealth: ["shadow"],
  Evasion: ["shadow"],
  Neurotoxin: ["arcane"],
  VenomousStrike: ["physical", "arcane"],
  ToxicExplosion: ["arcane"],
  Venomborn: ["arcane"],
  Focus: ["shadow"],
  Recouperate: ["shadow"],
  SlowingVenom: ["physical", "arcane"],
  WeakeningVenom: ["physical", "arcane"],
  RabidVenom: ["physical", "arcane"],
  CheapShot: ["physical"],
  Pandemic: ["arcane"],
  Epidemic: ["arcane", "shadow"],
  LightningStrike: ["lightning", "physical"],
  LightSpeed: ["lightning", "physical"],
  CullTheWeak: ["arcane", "physical"],
  Combustion: ["fire"],
  ArcaneCombustion: ["fire", "arcane"],
  Thundersnow: ["frost", "lightning"],
  SelfImmolation: ["fire"],
  ArcaneBarrier: ["arcane"],
  FrozenPath: ["frost"],
  Conductor: ["lightning"],
  ManaFracture: ["arcane"],
  RideTheLightning: ["lightning"],
  SearingStrike: ["fire", "physical"],
  FlameCleave: ["fire", "physical"],
  HolyStrike: ["arcane", "physical"],
  Unbreakable: ["physical"],
  BloodBarrier: ["physical"],
  BurningGuard: ["fire", "physical"],
  LayOnHands: ["arcane"],
  FireEater: ["fire"],
  FurnaceBreaker: ["physical", "fire"],
  ExplosiveStrike: ["physical", "fire"],
  BeaconOfLight: ["arcane"],
};

function resolveAbilityTypes(ability: AbilityDefinition): DamageType[] {
  if (ability.types?.length) return [...new Set(ability.types)];
  if (ABILITY_TYPE_OVERRIDES[ability.id]) return [...ABILITY_TYPE_OVERRIDES[ability.id]];
  const componentTypes = ability.damageComponents?.map((component) => component.damageType) ?? [];
  if (componentTypes.length > 0) return [...new Set(componentTypes)];
  if (ability.damageType) return [ability.damageType];
  return [ability.branch === "shadow" ? "shadow" : ability.branch === "arcanist" ? "arcane" : "physical"];
}

